// Parser do HTML do Google Shopping
const html = $input.first().json.data;
const produto_buscado = $('⚙️ Configurar Variáveis').first().json.produto;
const preco_min = $('⚙️ Configurar Variáveis').first().json.preco_min;
const preco_max = $('⚙️ Configurar Variáveis').first().json.preco_max;
const busca_id = $('⚙️ Configurar Variáveis').first().json.busca_id;

const resultados = [];

// Extrair blocos de produtos do Google Shopping
// Pattern para capturar dados dos cards de produto
const productPattern = /<div[^>]*class="[^"]*sh-dgr__content[^"]*"[^>]*>(.*?)<\/div>\s*<\/div>/gs;
const namePattern = /<h3[^>]*class="[^"]*tAxDx[^"]*"[^>]*>([^<]+)<\/h3>/;
const pricePattern = /class="[^"]*a8Pemb[^"]*"[^>]*>([^<]+)<\/span>/;
const linkPattern = /<a[^>]*href="(\/shopping\/product[^"]+|https?:[^"]+)"[^>]*>/;
const sellerPattern = /class="[^"]*aULzUe[^"]*"[^>]*>([^<]+)<\/span>/;

// Método alternativo: buscar por padrão de preço em Reais
const altProductPattern = /data-sh-or="([^"]+)"[^>]*>.*?<span[^>]*class="[^"]*a8Pemb[^"]*"[^>]*>R\$\s*([\d.,]+).*?<h3[^>]*>([^<]+)<\/h3>.*?href="([^"]+)"/gs;

// Tentar extração primária
let matches;
const priceBlocks = html.match(/R\$[\s\d.,]+/g) || [];

// Extração robusta por regex em múltiplas passagens
const linkMatches = html.match(/href="(https:\/\/www\.google\.com\/shopping\/product\/[^"]+)"/g) || [];
const nameMatches = html.match(/<h3[^>]*class="[^"]*tAxDx[^"]*"[^>]*>([^<]+)<\/h3>/g) || [];
const priceMatches = html.match(/class="[^"]*a8Pemb[^"]*OFFNJ[^"]*"[^>]*>R\$&nbsp;([\d.,]+)<\/span>/g) || 
                    html.match(/class="[^"]*a8Pemb[^"]*"[^>]*>R\$\s*([\d.,]+)<\/span>/g) || [];

// Construir resultados
const count = Math.min(nameMatches.length, priceMatches.length, linkMatches.length);

for (let i = 0; i < count; i++) {
  try {
    const nameMatch = nameMatches[i]?.match(/>([^<]+)<\/h3>/);
    const priceMatch = priceMatches[i]?.match(/R\$[&nbsp;\s]*([\d.,]+)/);
    const linkMatch = linkMatches[i]?.match(/href="([^"]+)"/);

    if (!nameMatch || !priceMatch) continue;

    const nome = nameMatch[1].trim();
    const precoStr = priceMatch[1].replace(/\./g, '').replace(',', '.');
    const preco = parseFloat(precoStr);
    const link = linkMatch ? linkMatch[1] : '';

    // Filtrar por faixa de preço
    if (preco < preco_min || preco > preco_max) continue;

    resultados.push({
      busca_id,
      produto_buscado,
      nome_produto: nome,
      preco_raw: `R$ ${priceMatch[1]}`,
      preco_numerico: preco,
      link_google: `https://www.google.com${link}`,
      link_produto: '',  // será preenchido no próximo step
      vendedor: '',      // será extraído ao visitar o link
      match_score: 0,    // será calculado pela IA
      analise_ia: '',
      data_coleta: new Date().toISOString()
    });
  } catch(e) {
    // Ignorar erros de parsing individual
    continue;
  }
}

// Se não encontrou nada, retornar item de erro
if (resultados.length === 0) {
  return [{
    json: {
      erro: 'Nenhum produto encontrado. Verifique a busca ou a chave da ScraperAPI.',
      html_length: html.length,
      produto_buscado
    }
  }];
}

return resultados.map(r => ({ json: r }));

// Extrair link real do marketplace a partir da página do Google Shopping
const html = $input.first().json.data || '';
const dadosProduto = $('🔄 Loop por Produto').first().json;

// Padrões para detectar links de marketplaces brasileiros
const marketplacePatterns = [
  { nome: 'Mercado Livre', pattern: /href="(https:\/\/[^"]*mercadolivre\.com\.br[^"]*)"/, regex_vendedor: /class="[^"]*ui-pdp-seller[^"]*"[^>]*>([^<]+)<\/span>/ },
  { nome: 'Amazon', pattern: /href="(https:\/\/[^"]*amazon\.com\.br[^"]*)"/, regex_vendedor: /#sellerProfileTriggerId[^>]*>([^<]+)<\/a>/ },
  { nome: 'Magazine Luiza', pattern: /href="(https:\/\/[^"]*magazineluiza\.com\.br[^"]*)"/, regex_vendedor: /seller-name[^>]*>([^<]+)</ },
  { nome: 'Americanas', pattern: /href="(https:\/\/[^"]*americanas\.com\.br[^"]*)"/, regex_vendedor: /sold-and-delivered[^>]*>([^<]+)</ },
  { nome: 'Casas Bahia', pattern: /href="(https:\/\/[^"]*casasbahia\.com\.br[^"]*)"/, regex_vendedor: /seller-info[^>]*>([^<]+)</ },
  { nome: 'Submarino', pattern: /href="(https:\/\/[^"]*submarino\.com\.br[^"]*)"/, regex_vendedor: /seller[^>]*>([^<]+)</ },
  { nome: 'Shopee', pattern: /href="(https:\/\/[^"]*shopee\.com\.br[^"]*)"/, regex_vendedor: /shopName[^>]*>([^<]+)</ },
  { nome: 'Kabum', pattern: /href="(https:\/\/[^"]*kabum\.com\.br[^"]*)"/, regex_vendedor: /seller[^>]*>([^<]+)</ }
];

let link_real = '';
let marketplace_detectado = 'Desconhecido';

// Tentar detectar o marketplace pelo link do Google Shopping
for (const mp of marketplacePatterns) {
  const match = html.match(mp.pattern);
  if (match) {
    link_real = match[1];
    marketplace_detectado = mp.nome;
    break;
  }
}

// Se não achou pelo HTML, tentar pela URL atual (após redirect)
if (!link_real) {
  const urlAtual = $input.first().json.url || '';
  for (const mp of marketplacePatterns) {
    if (mp.pattern.test(urlAtual)) {
      link_real = urlAtual;
      marketplace_detectado = mp.nome;
      break;
    }
  }
}

return [{
  json: {
    ...dadosProduto,
    link_produto: link_real || dadosProduto.link_google,
    marketplace: marketplace_detectado,
    precisa_visitar: link_real !== ''
  }
}];

// Extrair vendedor de acordo com o marketplace detectado
const html = $input.first().json.data || '';
const dadosProduto = $('🏪 Detectar Marketplace').first().json;
const marketplace = dadosProduto.marketplace;

let vendedor = 'Não identificado';

// Padrões específicos por marketplace
const extractors = {
  'Mercado Livre': [
    /class="[^"]*ui-pdp-seller__link-trigger[^"]*"[^>]*>([^<]+)<\/a>/,
    /Vendido por<\/span>\s*<span[^>]*>([^<]+)<\/span>/,
    /"sellerNickname":"([^"]+)"/
  ],
  'Amazon': [
    /id="sellerProfileTriggerId"[^>]*>([^<]+)<\/a>/,
    /"seller":\{"displayName":"([^"]+)"/,
    /Vendido por:?<\/span>\s*<span[^>]*>([^<]+)<\/span>/
  ],
  'Magazine Luiza': [
    /class="[^"]*seller-name[^"]*"[^>]*>([^<]+)</,
    /"sellerName":"([^"]+)"/,
    /Vendedor:\s*([^<"]+)/
  ],
  'Americanas': [
    /class="[^"]*soldBy[^"]*"[^>]*>([^<]+)</,
    /"sellerName":"([^"]+)"/
  ],
  'Casas Bahia': [
    /Vendido e entregue por<[^>]+>([^<]+)</,
    /"sellerName":"([^"]+)"/
  ],
  'Shopee': [
    /class="[^"]*shopName[^"]*"[^>]*>([^<]+)</,
    /"shopName":"([^"]+)"/
  ]
};

const patterns = extractors[marketplace] || [];

for (const pattern of patterns) {
  const match = html.match(pattern);
  if (match && match[1]) {
    vendedor = match[1].trim().replace(/&amp;/g, '&').replace(/&#039;/g, "'");
    break;
  }
}

// Fallback: tentar extrair do JSON-LD (dados estruturados)
if (vendedor === 'Não identificado') {
  const jsonLdMatch = html.match(/<script type="application\/ld\+json">([^<]+)<\/script>/g);
  if (jsonLdMatch) {
    for (const block of jsonLdMatch) {
      try {
        const cleanBlock = block.replace(/<script[^>]*>/, '').replace(/<\/script>/, '');
        const data = JSON.parse(cleanBlock);
        if (data.seller?.name) { vendedor = data.seller.name; break; }
        if (data.brand?.name) { vendedor = data.brand.name; break; }
      } catch(e) {}
    }
  }
}

return [{
  json: {
    ...dadosProduto,
    vendedor
  }
}];

// Combinar dados do produto com análise da IA
const resposta_ia = $input.first().json;
const dadosProduto = $('👤 Extrair Vendedor').first().json;

let analise = {};
try {
  // Extrair texto da resposta do Claude
  const texto_ia = resposta_ia.content[0].text;
  // Limpar possíveis blocos de código
  const json_limpo = texto_ia.replace(/```json/g, '').replace(/```/g, '').trim();
  analise = JSON.parse(json_limpo);
} catch(e) {
  analise = {
    match_score: 0,
    e_mesmo_produto: 'erro',
    justificativa: 'Erro ao processar análise',
    alerta: 'Falha no parsing da resposta da IA'
  };
}

// Formatar para o Google Sheets
const agora = new Date();
const dataFormatada = agora.toLocaleDateString('pt-BR');
const horaFormatada = agora.toLocaleTimeString('pt-BR');

return [{
  json: {
    // Identificação
    data: dataFormatada,
    hora: horaFormatada,
    busca_id: dadosProduto.busca_id,

    // Busca
    produto_buscado: dadosProduto.produto_buscado,

    // Produto encontrado  
    nome_produto: dadosProduto.nome_produto,
    preco: dadosProduto.preco_raw,
    preco_numerico: dadosProduto.preco_numerico,
    marketplace: dadosProduto.marketplace,
    vendedor: dadosProduto.vendedor,
    link: dadosProduto.link_produto || dadosProduto.link_google,

    // Análise IA
    match_score: analise.match_score || 0,
    e_mesmo_produto: analise.e_mesmo_produto || 'erro',
    caracteristicas: (analise.caracteristicas_encontradas || []).join(', '),
    faltando: (analise.caracteristicas_faltando || []).join(', '),
    preco_adequado: analise.preco_adequado || 'indefinido',
    justificativa: analise.justificativa || '',
    alerta: analise.alerta || ''
  }
}];

